const rawData = $input.first().json;
const lineData = rawData.body || rawData;
const events = lineData.events || [];
const event = events[0];
if (!event) return [{ json: { valid: false, errorMessage: 'イベントなし' } }];
const userId = event.source?.userId || '';
const replyToken = event.replyToken || '';
const msgType = event.message?.type || '';
const msgText = (event.message?.text || '').trim();
const now = new Date();
const jst = new Date(now.getTime() + 9 * 3600000);
const y = jst.getFullYear(), mo = jst.getMonth() + 1;
const dd = String(jst.getDate()).padStart(2,'0');
const today = `${y}/${String(mo).padStart(2,'0')}/${dd}`;
const defaultFile = `経営管理_${y}年${mo}月.xlsx`;
const claudeKey = 'YOUR_CLAUDE_API_KEY';
const lineToken = 'Bearer YOUR_EXPENSE_LINE_TOKEN';

// PDFファイル → Phase 2-2: 外注請求書PDF処理
if (msgType === 'file') {
  const pdfRes = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api-data.line.me/v2/bot/message/${event.message.id}/content`,
    headers: { 'Authorization': lineToken },
    encoding: 'arraybuffer', returnFullResponse: false
  });
  const base64Pdf = Buffer.from(pdfRes).toString('base64');

  const pdfPrompt = `今日は${today}です。このPDFを解析しJSONのみで返答。

請求書の種類を判定してデータを抽出してください。

種類:
- subcontractor_invoice: 外注業者からの請求書（当社が支払う側）
- sales_invoice: 売上請求書（当社が請求する側）
- payslip: 給与明細
- other: その他

返答例:
subcontractor_invoice: {"docType":"subcontractor_invoice","registrationDate":"${today}","invoiceDate":"${today}","vendorName":"梶原通信","projectName":"△△工事","amountExTax":50000,"tax":5000,"totalAmount":55000}
sales_invoice: {"docType":"sales_invoice","registrationDate":"${today}","clientName":"港振興業株式会社","projectName":"△△工事","amountExTax":100000,"tax":10000,"totalAmount":110000,"invoiceDate":"${today}","paymentDueDate":"2026/05/31"}
payslip: {"docType":"payslip","employeeName":"野添優","paymentDate":"${today}","baseSalary":250000,"totalAllowances":30000,"grossPay":280000,"socialInsurance":40000,"incomeTax":8000,"residenceTax":12000,"totalDeductions":60000,"netPay":220000}
other: {"docType":"other"}`;

  const pdfApiRes = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.anthropic.com/v1/messages',
    headers: { 'x-api-key': claudeKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: {
      model: 'claude-haiku-4-5-20251001', max_tokens: 400,
      messages: [{ role: 'user', content: [
        { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: base64Pdf } },
        { type: 'text', text: pdfPrompt }
      ]}]
    }, json: true
  });

  let pdfParsed;
  try {
    const txt = pdfApiRes.content[0].text.trim();
    pdfParsed = JSON.parse((txt.match(/\{[\s\S]*\}/) || [txt])[0]);
  } catch(e) {
    return [{ json: { valid: false, replyToken, errorMessage: 'PDFを読み取れませんでした。\n再度送信してください。' } }];
  }

  if (pdfParsed.docType === 'subcontractor_invoice') {
    const ds = pdfParsed.registrationDate || today;
    const dp = ds.split('/');
    const ty = parseInt(dp[0]), tm = parseInt(dp[1]);
    return [{ json: { valid: true, messageType: 'subcontractor_invoice', ...pdfParsed, userId, replyToken,
      fileName: `経営管理_${ty}年${tm}月.xlsx`, targetYear: ty, targetMonth: tm } }];
  }
  if (pdfParsed.docType === 'sales_invoice') {
    const ds = pdfParsed.invoiceDate || pdfParsed.registrationDate || today;
    const dp = ds.split('/');
    const ty = parseInt(dp[0]), tm = parseInt(dp[1]);
    return [{ json: { valid: true, messageType: 'sales', ...pdfParsed, registrationDate: today, userId, replyToken,
      fileName: `経営管理_${ty}年${tm}月.xlsx`, targetYear: ty, targetMonth: tm } }];
  }
  if (pdfParsed.docType === 'payslip') {
    const ds = pdfParsed.paymentDate || today;
    const dp = ds.split('/');
    const ty = parseInt(dp[0]), tm = parseInt(dp[1]);
    return [{ json: { valid: true, messageType: 'payslip', ...pdfParsed, registrationDate: today, userId, replyToken,
      fileName: `経営管理_${ty}年${tm}月.xlsx`, targetYear: ty, targetMonth: tm } }];
  }
  return [{ json: { valid: false, replyToken, errorMessage: `PDFの内容を認識できませんでした。\n外注請求書のPDFを送信してください。` } }];
}

// 画像 → Phase 2-1: レシート・通帳・クレカ明細の写真
if (msgType === 'image') {
  const imgRes = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api-data.line.me/v2/bot/message/${event.message.id}/content`,
    headers: { 'Authorization': lineToken },
    encoding: 'arraybuffer', returnFullResponse: false
  });
  const base64Img = Buffer.from(imgRes).toString('base64');

  const imgPrompt = `今日は${today}です。この画像を解析しJSONのみ返答。

判定タイプ:
- receipt: レシート・領収書（1件の経費）
- subcontractor_invoice: 外注業者からの請求書（当社が支払う側）
- sales_invoice: 売上請求書（当社が請求する側）
- bank_statement: 通帳・引き落とし明細（複数件）
- credit_card: クレジットカード明細（複数件）
- unknown: 判断できない

勘定科目:
◎: 旅費交通費/通信費/水道光熱費/荷造運賃/外注費/広告宣伝費/支払手数料/保険料/租税公課/リース料/支払利息/消耗品費/法定福利費/諸会費/新聞図書費/雑費
⚠要確認: 会議費/接待交際費/地代家賃/車両運搬具/福利厚生費/給与/減価償却費
requiresReview: ⚠はtrue、それ以外はfalse

返答例:
receipt: {"imageType":"receipt","messageType":"expense","date":"${today}","expenseCategory":"消耗品費","requiresReview":false,"paymentMethod":"現金","storeName":"セブンイレブン","amount":550,"note":""}
subcontractor_invoice: {"imageType":"subcontractor_invoice","registrationDate":"${today}","invoiceDate":"${today}","vendorName":"梶原通信","projectName":"△△工事","amountExTax":50000,"tax":5000,"totalAmount":55000}
sales_invoice: {"imageType":"sales_invoice","registrationDate":"${today}","clientName":"港振興業株式会社","projectName":"△△工事","amountExTax":100000,"tax":10000,"totalAmount":110000,"invoiceDate":"${today}","paymentDueDate":"2026/05/31"}
bank_statement/credit_card: {"imageType":"bank_statement","entries":[{"date":"${today}","expenseCategory":"水道光熱費","requiresReview":false,"storeName":"東京電力","amount":15000,"paymentMethod":"口座引落"}]}
unknown: {"imageType":"unknown"}`;

  const res = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.anthropic.com/v1/messages',
    headers: { 'x-api-key': claudeKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: {
      model: 'claude-haiku-4-5-20251001', max_tokens: 800,
      messages: [{ role: 'user', content: [
        { type: 'image', source: { type: 'base64', media_type: 'image/jpeg', data: base64Img } },
        { type: 'text', text: imgPrompt }
      ]}]
    }, json: true
  });

  let parsed;
  try {
    const txt = res.content[0].text.trim();
    parsed = JSON.parse((txt.match(/\{[\s\S]*\}/) || [txt])[0]);
  } catch(e) {
    return [{ json: { valid: false, replyToken, errorMessage: '画像を読み取れませんでした。\nもう一度送信してください。' } }];
  }

  if (parsed.imageType === 'unknown') {
    return [{ json: { valid: false, replyToken, errorMessage: '画像の内容を判別できませんでした。\nレシート・通帳・クレカ明細の写真を送信してください。' } }];
  }

  // レシート1件
  if (parsed.imageType === 'receipt') {
    const ds = parsed.date || today;
    const dp = ds.split('/');
    const ty = parseInt(dp[0]), tm = parseInt(dp[1]);
    return [{ json: { valid: true, ...parsed, userId, replyToken,
      fileName: `経営管理_${ty}年${tm}月.xlsx`, targetYear: ty, targetMonth: tm } }];
  }

  // 外注請求書（画像）
  if (parsed.imageType === 'subcontractor_invoice') {
    const ds = parsed.registrationDate || today;
    const dp = ds.split('/');
    const ty = parseInt(dp[0]), tm = parseInt(dp[1]);
    return [{ json: { valid: true, messageType: 'subcontractor_invoice', ...parsed, userId, replyToken,
      fileName: `経営管理_${ty}年${tm}月.xlsx`, targetYear: ty, targetMonth: tm } }];
  }

  // 売上請求書（画像）
  if (parsed.imageType === 'sales_invoice') {
    const ds = parsed.invoiceDate || parsed.registrationDate || today;
    const dp = ds.split('/');
    const ty = parseInt(dp[0]), tm = parseInt(dp[1]);
    return [{ json: { valid: true, messageType: 'sales', ...parsed, registrationDate: today, userId, replyToken,
      fileName: `経営管理_${ty}年${tm}月.xlsx`, targetYear: ty, targetMonth: tm } }];
  }

  // 通帳・クレカ明細（複数件）
  if (parsed.entries && parsed.entries.length > 0) {
    const ds = parsed.entries[0].date || today;
    const dp = ds.split('/');
    const ty = parseInt(dp[0]), tm = parseInt(dp[1]);
    return [{ json: { valid: true, messageType: 'multi_expense', imageType: parsed.imageType,
      entries: parsed.entries, userId, replyToken,
      fileName: `経営管理_${ty}年${tm}月.xlsx`, targetYear: ty, targetMonth: tm } }];
  }

  return [{ json: { valid: false, replyToken, errorMessage: '画像の解析結果を処理できませんでした。' } }];
}

if (msgType !== 'text') {
  return [{ json: { valid: false, replyToken, errorMessage: 'テキストまたは画像のみ対応しています' } }];
}
if (msgText === 'ヘルプ' || msgText === 'help') {
  return [{ json: { valid: true, messageType: 'query_help', userId, replyToken,
    fileName: defaultFile, targetYear: y, targetMonth: mo } }];
}

const prompt = `今日は${today}です。以下のメッセージを解析しJSONのみ返答。

メッセージ:「${msgText}」

分類:
- expense: 経費（現金払い・小口経費）
- subcontractor_invoice: 外注業者からの請求書受け取り（外注費の登録）
- subcontractor_payment: 外注業者への支払い記録
- sales: 売上・請求登録
- payment_received: 売上の入金記録
- query: 照会
- unknown: 不明

【勘定科目一覧（expenseCategoryに使用）】
◎原則OK: 旅費交通費（電車代・高速代・駐車場代・宿泊代）/通信費（切手・電話・FAX・インターネット）/水道光熱費（電気・ガス・水道）/荷造運賃（宅急便代）/外注費（業務委託費）/広告宣伝費（掲載料・チラシ・贈答用品）/支払手数料（振込手数料）/保険料（火災・自動車保険）/租税公課（印紙税・自動車税）/リース料（複合機・車リース）/支払利息（借入金利息）/消耗品費（10万未満PC・コピー代・文房具）/法定福利費（健康保険・労災・雇用保険事業主分）/諸会費（業界団体年会費・カード年会費）/新聞図書費（業務関連書籍・新聞）/雑費（いずれにも該当しない経費）
⚠要確認: 会議費（会議の飲食代・会場費）/接待交際費（取引先ゴルフ・慶弔金・手土産・飲食）/地代家賃（事務所・店舗家賃・月極駐車場）/車両運搬具（車両購入）/福利厚生費（健康診断・慰安旅行）/給与（従業員給料・賃金・手当・賞与）/減価償却費（固定資産の今年の償却額）

requiresReview: ⚠要確認の種別はtrue、それ以外はfalse

queryType候補: 未払い確認/未入金確認/今月サマリー/粗利確認/支払期限確認/経費詳細/特定種別詳細/給与サマリー/従業員別給与/業者別外注費/案件別外注費/得意先別売上/案件別売上/入金済み確認/今月収支/来月支払予定/滞留確認/前月比較/四半期サマリー/今月グラフ/今年グラフ/前年比較

返答例:
expense(OK): {"messageType":"expense","date":"${today}","expenseCategory":"消耗品費","requiresReview":false,"paymentMethod":"現金","storeName":"コメリ","projectName":"","amount":5000,"note":""}
expense(要確認): {"messageType":"expense","date":"${today}","expenseCategory":"接待交際費","requiresReview":true,"paymentMethod":"現金","storeName":"○○食堂","projectName":"","amount":15000,"note":""}
subcontractor_invoice: {"messageType":"subcontractor_invoice","registrationDate":"${today}","vendorName":"梶原通信","projectName":"△△工事","amountExTax":50000,"tax":5000,"totalAmount":55000}
subcontractor_payment: {"messageType":"subcontractor_payment","vendorName":"梶原通信","paymentAmount":55000,"paymentDate":"${today}"}
sales: {"messageType":"sales","registrationDate":"${today}","clientName":"港振興業株式会社","projectName":"△△工事","amountExTax":100000,"tax":10000,"totalAmount":110000,"invoiceDate":"${today}","paymentDueDate":"2026/05/31"}
payment_received: {"messageType":"payment_received","clientName":"港振興業株式会社","receivedAmount":110000,"receivedDate":"${today}"}
query: {"messageType":"query","queryType":"未払い確認"}
特定種別: {"messageType":"query","queryType":"特定種別詳細","targetCategory":"旅費交通費"}
従業員別給与: {"messageType":"query","queryType":"従業員別給与","targetEmployee":"野添優"}
前年比較: {"messageType":"query","queryType":"前年比較"}`;

const res = await this.helpers.httpRequest({
  method: 'POST', url: 'https://api.anthropic.com/v1/messages',
  headers: { 'x-api-key': claudeKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
  body: { model: 'claude-haiku-4-5-20251001', max_tokens: 500,
    messages: [{ role: 'user', content: prompt }] },
  json: true
});
let parsed;
try {
  const txt = res.content[0].text.trim();
  parsed = JSON.parse((txt.match(/\{[\s\S]*\}/) || [txt])[0]);
} catch(e) {
  return [{ json: { valid: false, replyToken, errorMessage: 'メッセージを解析できませんでした。再送してください。' } }];
}
if (parsed.messageType === 'unknown') {
  return [{ json: { valid: false, replyToken, errorMessage: '内容を認識できませんでした。\n「ヘルプ」で使い方を確認できます。' } }];
}
const ds = parsed.date || parsed.registrationDate || today;
const dp = ds.split('/');
const ty = parseInt(dp[0]), tm = parseInt(dp[1]);
return [{ json: { valid: true, ...parsed, userId, replyToken,
  fileName: `経営管理_${ty}年${tm}月.xlsx`, targetYear: ty, targetMonth: tm } }];

const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('LINEメッセージ解析').first().json;
  const fileInfo = $('月次ファイル情報取得').first().json;
  try {
    const wb = new ExcelJS.Workbook();
    const dlUrl = fileInfo['@microsoft.graph.downloadUrl'];
    if (dlUrl) {
      try {
        const r = await this.helpers.httpRequest({ method:'GET', url:dlUrl, encoding:'arraybuffer', returnFullResponse:false });
        await wb.xlsx.load(Buffer.from(r), { useSharedStrings: false });
      } catch(e) {}
    }
    const toDate = s => { if(!s)return null; const p=s.split('/'); return new Date(Date.UTC(+p[0],+p[1]-1,+p[2])); };
    // 会社別 入金期限ルール
    const PAYMENT_RULES = {
      'オークコミュニケーション': { months: 2, day: 10 },  // 翌々月10日
      '平成システム': { cutoffDay: 20 }                    // 20日締め翌月末
    };
    const calcPaymentDue = (regDateStr, clientName) => {
      const rd = toDate(regDateStr);
      if (!rd) return null;
      const rule = PAYMENT_RULES[clientName];
      if (rule) {
        if (rule.cutoffDay) {
          // N日締め: 登録日<=締日→当月締め翌月末, >締日→翌月締め翌々月末
          const add = rd.getDate() <= rule.cutoffDay ? 1 : 2;
          return new Date(Date.UTC(rd.getFullYear(), rd.getMonth() + add + 1, 0));
        }
        const dm = rd.getMonth() + rule.months;
        return new Date(Date.UTC(rd.getFullYear() + Math.floor(dm/12), dm%12, rule.day));
      }
      // デフォルト: 翌月末
      return new Date(Date.UTC(rd.getFullYear(), rd.getMonth()+2, 0));
    };
    const getV = c => (c&&typeof c==='object'&&'result'in c)?c.result:c;
    // 外注業者別 支払期限ルール
    const SUBCON_RULES = {
      '秀電工': { months: 2, day: 10 }  // 翌々月10日（服部秀一の屋号）
    };
    const calcSubconDue = (regDateStr, vendorName) => {
      const rd = toDate(regDateStr);
      if (!rd) return null;
      const rule = SUBCON_RULES[vendorName];
      if (rule) {
        const dm = rd.getMonth() + rule.months;
        return new Date(Date.UTC(rd.getFullYear() + Math.floor(dm/12), dm%12, rule.day));
      }
      return new Date(Date.UTC(rd.getFullYear(), rd.getMonth()+2, 0));
    };
    const ensure = (name, hdrs) => {
      let s = wb.getWorksheet(name);
      if (!s) { s=wb.addWorksheet(name); const h=s.getRow(1); hdrs.forEach((v,i)=>h.getCell(i+1).value=v); h.font={bold:true}; h.commit(); }
      return s;
    };
    const lastR = (s, col) => { let r=1; s.eachRow((row,n)=>{ if(n>=2&&getV(row.getCell(col).value)!=null&&getV(row.getCell(col).value)!=='')r=n; }); return r; };
    const mt = data.messageType;

    if (mt === 'expense') {
      const s = ensure('経費', ['No','日付','経費種類','支払方法','店名・支払先','案件名','金額（税込）','備考','確認フラグ']);
      const nr = lastR(s,2)+1; const row = s.getRow(nr);
      row.getCell(1).value=nr-1;
      row.getCell(2).value=toDate(data.date); row.getCell(2).numFmt='YYYY/MM/DD';
      row.getCell(3).value=data.expenseCategory; row.getCell(4).value=data.paymentMethod;
      row.getCell(5).value=data.storeName; row.getCell(6).value=data.projectName||'';
      row.getCell(7).value=data.amount; row.getCell(7).numFmt='#,##0';
      row.getCell(8).value=data.note||''; row.getCell(9).value=data.requiresReview?'⚠ 要確認':''; row.commit();

    } else if (mt === 'multi_expense') {
      // 通帳・クレカ明細の複数件経費
      const s = ensure('経費', ['No','日付','経費種類','支払方法','店名・支払先','案件名','金額（税込）','備考','確認フラグ']);
      const entries = data.entries || [];
      let totalAmt = 0; let hasReview = false;
      for (const entry of entries) {
        const nr = lastR(s,2)+1; const row = s.getRow(nr);
        const amt = entry.amount || 0;
        row.getCell(1).value = nr-1;
        row.getCell(2).value = toDate(entry.date); row.getCell(2).numFmt='YYYY/MM/DD';
        row.getCell(3).value = entry.expenseCategory||'雑費';
        row.getCell(4).value = entry.paymentMethod||'口座引落';
        row.getCell(5).value = entry.storeName||'';
        row.getCell(7).value = amt; row.getCell(7).numFmt='#,##0';
        row.getCell(9).value = entry.requiresReview ? '⚠ 要確認' : '';
        row.commit();
        totalAmt += amt;
        if (entry.requiresReview) hasReview = true;
      }
      data.entryCount = entries.length;
      data.totalAmount = totalAmt;
      data.hasReview = hasReview;

    } else if (mt === 'subcontractor_invoice') {
      const s = ensure('外注管理', ['No','登録日','業者名','種別','インボイス','案件名','請求額(税抜)','消費税(10%)','合計(税込)','請求日','支払期限','支払日','支払額','状況']);
      const nr = lastR(s,2)+1; const row = s.getRow(nr);
      const exTax = data.amountExTax || 0;
      const tax = data.tax !== undefined ? data.tax : Math.floor(exTax * 0.1);
      const total = data.totalAmount || (exTax + tax);
      const due = calcSubconDue(data.registrationDate, data.vendorName);
      const dueStr = due ? `${due.getUTCFullYear()}/${String(due.getUTCMonth()+1).padStart(2,'0')}/${String(due.getUTCDate()).padStart(2,'0')}` : '';
      row.getCell(1).value=nr-1;
      row.getCell(2).value=toDate(data.registrationDate); row.getCell(2).numFmt='YYYY/MM/DD';
      row.getCell(3).value=data.vendorName;
      row.getCell(6).value=data.projectName||'';
      row.getCell(7).value=exTax; row.getCell(7).numFmt='#,##0';
      row.getCell(8).value=tax; row.getCell(8).numFmt='#,##0';
      row.getCell(9).value=total; row.getCell(9).numFmt='#,##0';
      const invDate = data.invoiceDate || data.registrationDate; row.getCell(10).value=toDate(invDate); row.getCell(10).numFmt='YYYY/MM/DD';
      if(due){row.getCell(11).value=due; row.getCell(11).numFmt='YYYY/MM/DD';}
      row.getCell(14).value='未払'; row.commit();
      data.calculatedDue = dueStr; data.totalAmount = total; data.tax = tax; data.amountExTax = exTax;

    } else if (mt === 'subcontractor_payment') {
