        const dl=info['@microsoft.graph.downloadUrl']; if(!dl)return null;
        const res=await this.helpers.httpRequest({method:'GET',url:dl,encoding:'arraybuffer',returnFullResponse:false});
        const b=new ExcelJS.Workbook(); await b.xlsx.load(Buffer.from(res),{useSharedStrings:false}); return b;
      }catch(e){return null;}
    };
    const [curWb,prevWb]=await Promise.all([loadYear(ty),loadYear(py)]);
    if(!prevWb){await sendText(`${py}年の年次データがまだありません。`); return [{json:{done:true}}];}
    const getAnnual=(book)=>{
      let sal=0,exp=0,sub=0;
      const mb=book&&book.getWorksheet('月別収支');
      if(mb)mb.eachRow((r,n)=>{if(n<2||n>13)return; sal+=(getV(r.getCell(2).value)||0); exp+=(getV(r.getCell(8).value)||0); sub+=(getV(r.getCell(5).value)||0);});
      return {sal,exp,sub,gross:sal-exp-sub};
    };
    const cur=getAnnual(curWb); const prev=getAnnual(prevWb);
    const arr=(c,p)=>c>p?'↑':c<p?'↓':'→';
    const pct=(c,p)=>p?`${((c-p)/p*100).toFixed(1)}%`:'N/A';
    const months=['1月','2月','3月','4月','5月','6月','7月','8月','9月','10月','11月','12月'];
    let mLines='';
    const curMb=curWb&&curWb.getWorksheet('月別収支'); const prevMb=prevWb&&prevWb.getWorksheet('月別収支');
    if(curMb&&prevMb){
      const mData=months.map((ml,i)=>{
        const cr=curMb.getRow(i+2), pr=prevMb.getRow(i+2);
        const cs=getV(cr.getCell(2).value)||0, ps=getV(pr.getCell(2).value)||0;
        const cg=getV(cr.getCell(10).value)||0, pg=getV(pr.getCell(10).value)||0;
        return `${ml}: 売上${arr(cs,ps)} 粗利${arr(cg,pg)}`;
      }).join(' / ');
      mLines=`\n\n月別トレンド(↑↓):\n${mData}`;
    }
    const msg=`【前年比較】\n${py}年 → ${ty}年\n\n売上:  ¥${fmt(prev.sal)} → ¥${fmt(cur.sal)} ${arr(cur.sal,prev.sal)} (${pct(cur.sal,prev.sal)})\n経費:  ¥${fmt(prev.exp)} → ¥${fmt(cur.exp)} ${arr(cur.exp,prev.exp)}\n外注費: ¥${fmt(prev.sub)} → ¥${fmt(cur.sub)} ${arr(cur.sub,prev.sub)}\n粗利:  ¥${fmt(prev.gross)} → ¥${fmt(cur.gross)} ${arr(cur.gross,prev.gross)} (${pct(cur.gross,prev.gross)})${mLines}`;
    return [{json:{replyToken,replyMessage:msg}}];
  }

    return [{ json: { replyToken, replyMessage: '照会コマンドが認識できませんでした。\n「ヘルプ」で確認してください。' } }];
})();

