const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('LINEメッセージ解析').first().json;
  const monthlyWb = new ExcelJS.Workbook();
  const monthlyFile = $('月次ファイル情報取得').first().json;
  const yearlyFile = $('年次ファイル情報取得').first().json;
  try {
    // 月次ファイルを読み込み
    const dlUrl = monthlyFile['@microsoft.graph.downloadUrl'];
    if (!dlUrl) return [{ json: { yearlyDone: false } }];
    const mRes = await this.helpers.httpRequest({ method:'GET', url:dlUrl, encoding:'arraybuffer', returnFullResponse:false });
    await monthlyWb.xlsx.load(Buffer.from(mRes), { useSharedStrings: false });
    const getV = c => (c&&typeof c==='object'&&'result'in c)?c.result:c;

    // 月次データ集計
    const expS=monthlyWb.getWorksheet('経費'), subS=monthlyWb.getWorksheet('外注管理'), salS=monthlyWb.getWorksheet('売上管理');
    const expCats=['旅費交通費','通信費','水道光熱費','荷造運賃','外注費','広告宣伝費','支払手数料','保険料','租税公課','リース料','支払利息','消耗品費','法定福利費','諸会費','新聞図書費','会議費','接待交際費','地代家賃','車両運搬具','福利厚生費','給与','減価償却費','雑費'];
    const byCat={};
    if(expS)expS.eachRow((r,n)=>{ if(n<2)return; const c=getV(r.getCell(3).value); const a=getV(r.getCell(7).value)||0; if(c)byCat[c]=(byCat[c]||0)+a; });
    const expTotal=Object.values(byCat).reduce((a,b)=>a+b,0);

    let salTotal=0,recvTotal=0;
    const byClient={};
    if(salS)salS.eachRow((r,n)=>{ if(n<2)return; const t=getV(r.getCell(7).value)||0; const st=getV(r.getCell(12).value); const cl=getV(r.getCell(3).value)||''; salTotal+=t; byClient[cl]=(byClient[cl]||0)+t; if(st==='入金済')recvTotal+=(getV(r.getCell(11).value)||t); });

    let subTotal=0,subPaid=0;
    const byVendor={};
    if(subS)subS.eachRow((r,n)=>{ if(n<2)return; const t=getV(r.getCell(9).value)||0; const st=getV(r.getCell(14).value); const vn=getV(r.getCell(3).value)||''; subTotal+=t; byVendor[vn]=(byVendor[vn]||0)+t; if(st==='支払済')subPaid+=(getV(r.getCell(13).value)||t); });

    const grossProfit=salTotal-subTotal-expTotal;
    const month=data.targetMonth; // 1-12
    const dataCol=month+1; // 月別シートは B列=1月, C列=2月...
    const monthLabel=`${month}月`;

    // 年次ファイル読み込み or 新規作成
    const yearlyWb = new ExcelJS.Workbook();
    const yDlUrl = yearlyFile['@microsoft.graph.downloadUrl'];
    if(yDlUrl){
      try{
        const yRes=await this.helpers.httpRequest({ method:'GET', url:yDlUrl, encoding:'arraybuffer', returnFullResponse:false });
        await yearlyWb.xlsx.load(Buffer.from(yRes),{useSharedStrings:false});
      }catch(e){}
    }

    // ① 月別収支シート更新
    let mbSheet=yearlyWb.getWorksheet('月別収支');
    if(!mbSheet){
      mbSheet=yearlyWb.addWorksheet('月別収支');
      const h=mbSheet.getRow(1);
      ['月','売上請求','入金済','未入金','外注費','外注支払','未払','経費','人件費','粗利（概算）'].forEach((v,i)=>h.getCell(i+1).value=v);
      h.font={bold:true}; h.commit();
      ['1月','2月','3月','4月','5月','6月','7月','8月','9月','10月','11月','12月'].forEach((ml,i)=>{
        const r=mbSheet.getRow(i+2); r.getCell(1).value=ml; r.commit();
      });
    }
    mbSheet.eachRow((row,n)=>{ if(n<2)return; if(getV(row.getCell(1).value)===monthLabel){
      row.getCell(2).value=salTotal; row.getCell(3).value=recvTotal; row.getCell(4).value=salTotal-recvTotal;
      row.getCell(5).value=subTotal; row.getCell(6).value=subPaid; row.getCell(7).value=subTotal-subPaid;
      row.getCell(8).value=expTotal; row.getCell(10).value=grossProfit;
      [2,3,4,5,6,7,8,9,10].forEach(c=>{row.getCell(c).numFmt='#,##0';});
      row.commit();
    }});

    // ② 業者別外注費シート更新
    let vSheet=yearlyWb.getWorksheet('業者別外注費');
    if(!vSheet){
      vSheet=yearlyWb.addWorksheet('業者別外注費');
      const h=vSheet.getRow(1);
      ['業者名','1月','2月','3月','4月','5月','6月','7月','8月','9月','10月','11月','12月','合計'].forEach((v,i)=>h.getCell(i+1).value=v);
      h.font={bold:true}; h.commit();
    }
    Object.entries(byVendor).forEach(([vendor,amt])=>{
      let found=false;
      vSheet.eachRow((row,n)=>{ if(n<2||found)return; if(getV(row.getCell(1).value)===vendor){
        row.getCell(dataCol).value=amt; row.getCell(dataCol).numFmt='#,##0'; row.commit(); found=true;
      }});
      if(!found){
        const nr=vSheet.lastRow?vSheet.lastRow.number+1:2;
        const row=vSheet.getRow(nr); row.getCell(1).value=vendor; row.getCell(dataCol).value=amt; row.getCell(dataCol).numFmt='#,##0'; row.commit();
      }
    });

    // ③ 得意先別売上シート更新
    let cSheet=yearlyWb.getWorksheet('得意先別売上');
    if(!cSheet){
      cSheet=yearlyWb.addWorksheet('得意先別売上');
      const h=cSheet.getRow(1);
      ['得意先名','1月','2月','3月','4月','5月','6月','7月','8月','9月','10月','11月','12月','合計'].forEach((v,i)=>h.getCell(i+1).value=v);
      h.font={bold:true}; h.commit();
    }
    Object.entries(byClient).forEach(([client,amt])=>{
      let found=false;
      cSheet.eachRow((row,n)=>{ if(n<2||found)return; if(getV(row.getCell(1).value)===client){
        row.getCell(dataCol).value=amt; row.getCell(dataCol).numFmt='#,##0'; row.commit(); found=true;
      }});
      if(!found){
        const nr=cSheet.lastRow?cSheet.lastRow.number+1:2;
        const row=cSheet.getRow(nr); row.getCell(1).value=client; row.getCell(dataCol).value=amt; row.getCell(dataCol).numFmt='#,##0'; row.commit();
      }
    });

    // ④ 経費種類別シート更新
    let eSheet=yearlyWb.getWorksheet('経費種類別');
    if(!eSheet){
      eSheet=yearlyWb.addWorksheet('経費種類別');
      const h=eSheet.getRow(1);
      ['経費種類','1月','2月','3月','4月','5月','6月','7月','8月','9月','10月','11月','12月','合計'].forEach((v,i)=>h.getCell(i+1).value=v);
      h.font={bold:true}; h.commit();
      expCats.forEach((cat,i)=>{ const r=eSheet.getRow(i+2); r.getCell(1).value=cat; r.commit(); });
    }
    expCats.forEach(cat=>{
      eSheet.eachRow((row,n)=>{ if(n<2)return; if(getV(row.getCell(1).value)===cat){
        row.getCell(dataCol).value=byCat[cat]||0; row.getCell(dataCol).numFmt='#,##0'; row.commit();
      }});
    });

    // 年次ファイルをアップロード
    const creds=await this.getCredentials('microsoftDriveOAuth2Api');
    const token=creds.oauthTokenData?.access_token;
    if(!token) return [{ json: { yearlyDone:false, reason:'token error' } }];
    const buf=await yearlyWb.xlsx.writeBuffer({useSharedStrings:false});
    const upUrl=yearlyFile.id
      ?`https://graph.microsoft.com/v1.0/me/drive/items/${yearlyFile.id}/content`
      :`https://graph.microsoft.com/v1.0/me/drive/root:/業務管理システム/経費管理/年次/年間サマリー_${data.targetYear}年.xlsx:/content`;
    await this.helpers.httpRequest({
      method:'PUT', url:upUrl,
      headers:{'Authorization':`Bearer ${token}`,'Content-Type':'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'},
      body:Buffer.from(buf), returnFullResponse:false
    });
    return [{ json: { yearlyDone:true } }];
  } catch(e) {
    return [{ json: { yearlyDone:false, reason:e.message } }];
  }
})();
